from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about an athlete into a fluent sentence."""
    if not triples:
        return ""

    # Group triples by subject
    from collections import defaultdict

    subj_map: dict[str, dict[str, list[str]]] = defaultdict(lambda: defaultdict(list))
    for t in triples:
        subj_map[t.subject][t.predicate].append(t.object)

    def join_list(items: list[str]) -> str:
        """Join a list with commas and an 'and' before the last item."""
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        return ", ".join(items[:-1]) + " and " + items[-1]

    # Helper to build a short clause for a subject (used for embedding)
    def build_clause(subj: str) -> str:
        """Create a concise clause describing subj using its predicates."""
        inner_parts = []
        for key in ["birthDate", "birthYear", "birthPlace", "height", "weight",
                    "currentclub", "club", "currentteam", "formerTeam",
                    "position", "league", "manager", "ground",
                    "draftYear", "draftRound", "draftPick",
                    "college", "youthclub"]:
            if key in subj_map[subj]:
                inner_parts.append(phrase(subj, key, subj_map[subj][key]))
        if not inner_parts:
            return ""
        if len(inner_parts) == 1:
            return inner_parts[0]
        return ", ".join(inner_parts[:-1]) + " and " + inner_parts[-1]

    # Predicates that may link to another entity whose description we can embed
    linking_predicates = {"draftTeam", "club", "currentteam", "formerTeam", "currentclub"}

    # Identify subjects that appear as objects of linking predicates so we can embed them
    linked_subjects = set()
    for t in triples:
        if t.predicate in linking_predicates:
            linked_subjects.add(t.object)

    def phrase(subject: str, pred: str, objs: list[str]) -> str:
        """Return a phrase (without leading subject) for a predicate and its objects,
        embedding descriptions of linked entities when appropriate."""
        # If the object is another subject and the predicate is linking, embed its clause
        if pred in linking_predicates and len(objs) == 1 and objs[0] in subj_map:
            linked = objs[0]
            clause = build_clause(linked)
            if clause:
                return f"{linked}, where {clause}"
        obj_str = join_list(objs)
        if pred == "birthDate":
            return f"was born on {obj_str}"
        if pred == "birthYear":
            return f"was born in {obj_str}"
        if pred == "birthPlace":
            return f"was born in {obj_str}"
        if pred == "height":
            return f"is {obj_str} metres tall"
        if pred == "weight":
            return f"weighs {obj_str}"
        if pred in ("club", "currentteam"):
            return f"plays for {obj_str}"
        if pred == "formerTeam":
            return f"formerly played for {obj_str}"
        if pred == "position":
            return f"plays in the {obj_str} position"
        if pred == "league":
            return f"competes in the {obj_str} league"
        if pred == "manager":
            return f"is managed by {obj_str}"
        if pred == "ground":
            return f"has home ground {obj_str}"
        if pred == "draftYear":
            return f"was drafted in {obj_str}"
        if pred == "draftRound":
            return f"was selected in round {obj_str}"
        if pred == "draftPick":
            return f"was the {obj_str}th pick"
        if pred == "college":
            return f"attended {obj_str}"
        if pred == "youthclub":
            return f"started at youth club {obj_str}"
        if pred == "currentclub":
            return f"currently plays for {obj_str}"
        if pred == "owner":
            return f"is owned by {obj_str}"
        if pred == "city":
            return f"is based in {obj_str}"
        if pred == "debutTeam":
            return f"made debut with {obj_str}"
        if pred == "draftTeam":
            return f"was drafted by {obj_str}"
        if pred == "playerNumber":
            return f"wears number {obj_str}"
        # generic fallback
        return f"{pred} {obj_str}"

    sentences = []
    for subject, preds in subj_map.items():
        # Skip subjects that are already embedded in another subject's clause
        if subject in linked_subjects:
            continue
        parts = []
        # Prioritise biographical info first
        for key in ["birthDate", "birthYear", "birthPlace", "height", "weight"]:
            if key in preds:
                parts.append(phrase(subject, key, preds[key]))
        # Then career info
        for key in ["currentclub", "club", "currentteam", "formerTeam", "position", "league", "manager", "ground", "draftYear", "draftRound", "draftPick", "college", "youthclub"]:
            if key in preds:
                parts.append(phrase(subject, key, preds[key]))
        # Any remaining predicates
        for key, objs in preds.items():
            if key not in {"birthDate","birthYear","birthPlace","height","weight","currentclub","club","currentteam","formerTeam","position","league","manager","ground","draftYear","draftRound","draftPick","college","youthclub"}:
                parts.append(phrase(subject, key, objs))

        if parts:
            # combine parts with commas and final 'and'
            if len(parts) == 1:
                sentence = f"{subject} {parts[0]}."
            else:
                sentence = f"{subject} " + ", ".join(parts[:-1]) + " and " + parts[-1] + "."
            sentences.append(sentence)

    # Join sentences about different subjects with a space
    return " ".join(sentences)

# EVOLVE-BLOCK-END

